const FALLBACK =
  "M60 40 L140 30 Q170 50 170 90 L160 120 Q150 150 120 160 L80 170 Q40 160 30 130 L30 80 Q30 50 60 40 Z";

/* ── Helper: find circuit path by track name ── */
function findCircuitPath(trackName: string): { path: string; isReal: boolean } {
  const key = Object.keys(CIRCUITS).find(
    k => trackName.toLowerCase().includes(k.toLowerCase())
  );
  const path = key ? CIRCUITS[key] : FALLBACK;
  const isReal = key ? path.length > 200 : false;
  return { path, isReal };
}

type SpeedOption = { label: string; ms: number };
const SPEED_OPTIONS: SpeedOption[] = [
  { label: '0.125x', ms: 76800 },
  { label: '0.25x', ms: 38400 },
  { label: '0.5x', ms: 19200 },
  { label: '1x', ms: 9600 },
  { label: '2x', ms: 4800 },
  { label: '5x', ms: 1920 },
  { label: '10x', ms: 960 },
];

const RaceReplay: React.FC<RaceReplayProps> = ({ lapData, totalLaps, trackName = '' }) => {
  const [pathEl, setPathEl] = useState<SVGPathElement | null>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const animationRef = useRef<number>(0);
  const timeRef = useRef<number>(0);

  const [currentLap, setCurrentLap] = useState(0);
  const [isPlaying, setIsPlaying] = useState(false);
  const [subLapProgress, setSubLapProgress] = useState(0);
  const [speedIdx, setSpeedIdx] = useState(2); // default 0.5x
  const [hoveredDriver, setHoveredDriver] = useState<string | null>(null);
  const [showTopN, setShowTopN] = useState(10); // how many drivers to show on track

  const lapDurationMs = SPEED_OPTIONS[speedIdx].ms;

  // Resolve circuit
  const { path: circuitPath, isReal } = useMemo(() => findCircuitPath(trackName), [trackName]);
  const viewBox = isReal ? '0 0 500 500' : '0 0 200 200';
  const strokeW = isReal ? 3 : 2;

  // Get path total length for positioning
  const [pathLength, setPathLength] = useState(0);
  useEffect(() => {
    if (pathEl) {
      setPathLength(pathEl.getTotalLength());
    }
  }, [pathEl, circuitPath]);

  // Get positions for a given lap
  const getPositionsForLap = useCallback(
    (lap: number): PositionEntry[] => {
      if (!lapData || lapData.length === 0) return [];
      const sorted = [...lapData].sort((a, b) => a.lap - b.lap);
      const match = sorted.find(l => l.lap === lap);
      if (match) return match.positions;
      const nearest = sorted.reduce((prev, curr) =>
        Math.abs(curr.lap - lap) < Math.abs(prev.lap - lap) ? curr : prev
      );
      return nearest.positions;
    },
    [lapData]
  );

  const maxLapNum = useMemo(() => {
    if (totalLaps > 0) return totalLaps;
    if (lapData.length > 0) return Math.max(...lapData.map(l => l.lap));
    return 1;
  }, [totalLaps, lapData]);

  // Interpolate positions between two laps
  const getInterpolatedPositions = useCallback(
    (lap: number, progress: number): PositionEntry[] => {
      const current = getPositionsForLap(lap);
      const next = getPositionsForLap(Math.min(lap + 1, maxLapNum));
      if (!current.length) return [];

      return current.map(entry => {
        const nextEntry = next.find(n => n.driver_name === entry.driver_name);
        if (!nextEntry) return entry;
        const interpPos = entry.position + (nextEntry.position - entry.position) * progress;
        return { ...entry, position: interpPos };
      });
    },
    [getPositionsForLap, maxLapNum]
  );

  // Animation loop
  useEffect(() => {
    if (!isPlaying) return;

    let lastTimestamp = 0;

    const loop = (timestamp: number) => {
      if (!lastTimestamp) lastTimestamp = timestamp;
      const delta = timestamp - lastTimestamp;
      lastTimestamp = timestamp;

      timeRef.current += delta;

      const totalProgress = timeRef.current / lapDurationMs;
      const lap = Math.floor(totalProgress);
      const subProgress = totalProgress - lap;

      if (lap >= maxLapNum) {
        setCurrentLap(maxLapNum);
        setSubLapProgress(0);
        setIsPlaying(false);
        return;
      }

      setCurrentLap(lap);
      setSubLapProgress(subProgress);

      animationRef.current = requestAnimationFrame(loop);
    };

    animationRef.current = requestAnimationFrame(loop);
    return () => cancelAnimationFrame(animationRef.current);
  }, [isPlaying, maxLapNum, lapDurationMs]);

  // Get point on path at a given fraction (0-1)
  const getPointOnPath = useCallback(
    (fraction: number): { x: number; y: number } => {
      if (!pathEl || pathLength === 0) return { x: 0, y: 0 };
      const len = ((fraction % 1) + 1) % 1 * pathLength;
      const pt = pathEl.getPointAtLength(len);
      return { x: pt.x, y: pt.y };
    },
    [pathEl, pathLength]
  );

  // Current driver positions
  const positions = useMemo(
    () => getInterpolatedPositions(currentLap, subLapProgress),
    [currentLap, subLapProgress, getInterpolatedPositions]
  );

  // Sorted full standings
  const sortedPositions = useMemo(
    () => [...positions].sort((a, b) => a.position - b.position),
    [positions]
  );

  // Only show top N on track to reduce clutter
  const visibleOnTrack = useMemo(
    () => sortedPositions.slice(0, showTopN),
    [sortedPositions, showTopN]
  );

  const maxPos = useMemo(
    () => Math.max(...(positions.map(p => p.position) || [20]), 20),
    [positions]
  );

  // Pre-compute start/finish line geometry
  const startFinishLine = useMemo(() => {
    if (!pathEl || pathLength === 0) return null;
    const p0 = pathEl.getPointAtLength(0);
    const p1 = pathEl.getPointAtLength(Math.min(10, pathLength));
    const dx = p1.x - p0.x;
    const dy = p1.y - p0.y;
    const len = Math.sqrt(dx * dx + dy * dy) || 1;
    return { x: p0.x, y: p0.y, nx: -dy / len, ny: dx / len };
  }, [pathEl, pathLength]);

  const handlePlayPause = () => {
    if (!isPlaying && currentLap >= maxLapNum) {
      timeRef.current = 0;
      setCurrentLap(0);
      setSubLapProgress(0);
    }
    if (!isPlaying) {
      timeRef.current = (currentLap + subLapProgress) * lapDurationMs;
    }
    setIsPlaying(prev => !prev);
  };

  const handleScrub = (e: React.ChangeEvent<HTMLInputElement>) => {
    const lap = parseInt(e.target.value, 10);
    setCurrentLap(lap);
    setSubLapProgress(0);
    timeRef.current = lap * lapDurationMs;
    setIsPlaying(false);
  };

  const stepLap = (dir: number) => {
    setIsPlaying(false);
    const newLap = Math.max(0, Math.min(maxLapNum, currentLap + dir));
    setCurrentLap(newLap);
    setSubLapProgress(0);
    timeRef.current = newLap * lapDurationMs;
  };

  // Get surname for labels
  const surname = (name: string) => {
    const parts = name.split(' ');
    return parts[parts.length - 1].slice(0, 3).toUpperCase();
  };

  const dotR = isReal ? 7 : 3.5;

  return (
    <div
      ref={containerRef}
      style={{
        background: 'rgba(255, 255, 255, 0.02)',
        border: '1px solid rgba(255, 255, 255, 0.06)',
        borderRadius: 16,
        padding: 16,
        width: '100%',
        boxSizing: 'border-box',
      }}
    >
      {/* ── Header row ── */}
      <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: 12, flexWrap: 'wrap', gap: 8 }}>
        <span style={{ fontFamily: 'Orbitron, sans-serif', fontSize: 14, color: 'rgba(255, 255, 255, 0.7)', letterSpacing: 1, textTransform: 'uppercase' }}>
          Race Replay {trackName && `— ${trackName}`}
        </span>
        <span style={{ fontFamily: 'Orbitron, sans-serif', fontSize: 18, color: '#e10600', fontWeight: 700 }}>
          Lap {currentLap} / {maxLapNum}
        </span>
      </div>

      {/* ── Main layout: Circuit + Live standings ── */}
      <div style={{ display: 'flex', gap: 16, alignItems: 'stretch' }}>

        {/* Circuit SVG */}
        <div style={{ flex: 1, minWidth: 0, position: 'relative' }}>
          <svg
            viewBox={viewBox}
            style={{ width: '100%', maxHeight: 420, borderRadius: 8, background: 'rgba(0, 0, 0, 0.3)' }}
            preserveAspectRatio="xMidYMid meet"
          >
            {/* Track surface */}
            <path d={circuitPath} fill="none" stroke="rgba(255, 255, 255, 0.06)" strokeWidth={strokeW * 10} strokeLinecap="round" strokeLinejoin="round" />
            {/* Track outline */}
            <path ref={setPathEl} d={circuitPath} fill="none" stroke="rgba(255, 255, 255, 0.18)" strokeWidth={strokeW} strokeLinecap="round" strokeLinejoin="round" />

            {/* Start/Finish line */}
            {startFinishLine && (() => {
              const { x, y, nx, ny } = startFinishLine;
              const ll = isReal ? 16 : 7;
              return (
                <g>
                  <line x1={x + nx * ll} y1={y + ny * ll} x2={x - nx * ll} y2={y - ny * ll}
                    stroke="white" strokeWidth={isReal ? 3 : 1.5} strokeDasharray={isReal ? '4 4' : '2 2'} opacity={0.7} />
                  <text x={x + nx * (ll + (isReal ? 14 : 6))} y={y + ny * (ll + (isReal ? 14 : 6))}
                    fill="rgba(255, 255, 255, 0.5)" fontSize={isReal ? 10 : 5} fontFamily="Orbitron, sans-serif" textAnchor="middle" dominantBaseline="middle">
                    S/F
                  </text>
                </g>
              );
            })()}

            {/* Driver dots — only visible top N, bottom rendered first so leaders are on top */}
            {[...visibleOnTrack].reverse().map(entry => {
              const fraction = subLapProgress - ((entry.position - 1) / maxPos) * 0.6;
              const normalizedFraction = ((fraction % 1) + 1) % 1;
              const point = getPointOnPath(normalizedFraction);
              if (point.x === 0 && point.y === 0) return null;

              const isHovered = hoveredDriver === entry.driver_name;
              const isTop5 = entry.position <= 5;
              const r = isHovered ? dotR * 1.3 : dotR;

              return (
                <g key={entry.driver_name}
                  onMouseEnter={() => setHoveredDriver(entry.driver_name)}
                  onMouseLeave={() => setHoveredDriver(null)}
                  style={{ cursor: 'pointer' }}
                >
                  {/* Glow */}
                  <circle cx={point.x} cy={point.y} r={r * 2.8} fill={entry.team_color} opacity={isHovered ? 0.4 : 0.15} />
                  {/* Dot */}
                  <circle cx={point.x} cy={point.y} r={r} fill={entry.team_color}
                    stroke={isHovered ? 'white' : 'rgba(0, 0, 0, 0.6)'} strokeWidth={isHovered ? (isReal ? 2 : 1) : (isReal ? 1.2 : 0.6)} />
                  {/* 3-letter name + position for top 5 or hovered */}
                  {(isTop5 || isHovered) && (
                    <g>
                      {/* Background pill */}
                      <rect
                        x={point.x - (isReal ? 18 : 9)}
                        y={point.y - r - (isReal ? 18 : 9)}
                        width={isReal ? 36 : 18}
                        height={isReal ? 13 : 6.5}
                        rx={isReal ? 3 : 1.5}
                        fill="rgba(0, 0, 0, 0.75)"
                        stroke={entry.team_color}
                        strokeWidth={isReal ? 0.8 : 0.4}
                      />
                      <text
                        x={point.x}
                        y={point.y - r - (isReal ? 10 : 5)}
                        fill="white"
                        fontSize={isReal ? 8.5 : 4.5}
                        fontFamily="Orbitron, sans-serif"
                        fontWeight={700}
                        textAnchor="middle"
                        dominantBaseline="middle"
                      >
                        P{Math.round(entry.position)} {surname(entry.driver_name)}
                      </text>
                    </g>
                  )}
                </g>
              );
            })}
          </svg>
        </div>

        {/* ── Live standings column ── */}
        <div style={{
          width: 200, flexShrink: 0, display: 'flex', flexDirection: 'column', gap: 0,
          background: 'rgba(0, 0, 0, 0.2)', borderRadius: 10, padding: '8px 0', maxHeight: 420, overflowY: 'auto',
        }}>
          <div style={{ padding: '0 10px 6px', borderBottom: '1px solid rgba(255, 255, 255, 0.08)' }}>
            <span style={{ fontFamily: 'Orbitron, sans-serif', fontSize: 9, color: 'rgba(255, 255, 255, 0.4)', textTransform: 'uppercase', letterSpacing: 1.5 }}>
              Live Standings
            </span>
          </div>
          {sortedPositions.map((entry, i) => {
            const pos = Math.round(entry.position);
            const isHighlighted = hoveredDriver === entry.driver_name;
            const isOnTrack = i < showTopN;
            return (
              <div
                key={entry.driver_name}
                onMouseEnter={() => setHoveredDriver(entry.driver_name)}
                onMouseLeave={() => setHoveredDriver(null)}
                style={{
                  display: 'flex', alignItems: 'center', gap: 6, padding: '4px 10px',
                  background: isHighlighted ? 'rgba(255, 255, 255, 0.08)' : 'transparent',
                  opacity: isOnTrack ? 1 : 0.4,
                  cursor: 'pointer', transition: 'background 0.15s',
                }}
              >
                <span style={{
                  fontFamily: 'Orbitron, sans-serif', fontSize: 10, color: pos <= 3 ? '#e10600' : 'rgba(255, 255, 255, 0.4)',
                  width: 18, textAlign: 'right', fontWeight: pos <= 3 ? 700 : 400,
                }}>
                  {pos}
                </span>
                <span style={{
                  width: 3, height: 16, borderRadius: 1.5, background: entry.team_color, flexShrink: 0,
                }} />
                <span style={{
                  fontSize: 11, color: isHighlighted ? 'white' : 'rgba(255, 255, 255, 0.7)',
                  whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis', flex: 1,
                  fontWeight: isHighlighted ? 600 : 400,
                }}>
                  {entry.driver_name}
                </span>
              </div>
            );
          })}
        </div>
      </div>

      {/* ── Controls bar ── */}
      <div style={{ display: 'flex', alignItems: 'center', gap: 10, marginTop: 14, flexWrap: 'wrap' }}>
        {/* Play/Pause */}
        <button onClick={handlePlayPause} style={{
          fontFamily: 'Orbitron, sans-serif', fontSize: 12, padding: '6px 18px', borderRadius: 8,
          border: '1px solid rgba(255, 255, 255, 0.15)',
          background: isPlaying ? 'rgba(225, 6, 0, 0.25)' : 'rgba(255, 255, 255, 0.06)',
          color: isPlaying ? '#e10600' : 'rgba(255, 255, 255, 0.8)',
          cursor: 'pointer', letterSpacing: 1, textTransform: 'uppercase', transition: 'all 0.2s ease',
        }}>
          {isPlaying ? '⏸ Pause' : '▶ Play'}
        </button>

        {/* Step buttons */}
        <div style={{ display: 'flex', gap: 3 }}>
          <button onClick={() => stepLap(-1)} title="Previous lap" style={stepBtnStyle}>⏮</button>
          <button onClick={() => stepLap(1)} title="Next lap" style={stepBtnStyle}>⏭</button>
        </div>

        {/* Scrubber */}
        <input type="range" min={0} max={maxLapNum} value={currentLap} onChange={handleScrub}
          style={{ flex: 1, minWidth: 80, accentColor: '#e10600', cursor: 'pointer' }} />

        {/* Speed selector */}
        <div style={{ display: 'flex', alignItems: 'center', gap: 4, background: 'rgba(255, 255, 255, 0.04)', borderRadius: 6, padding: 2 }}>
          {SPEED_OPTIONS.map((opt, i) => (
            <button
              key={opt.label}
              onClick={() => {
                // Recalc time so position stays the same at new speed
                const currentProgress = (currentLap + subLapProgress);
                setSpeedIdx(i);
                timeRef.current = currentProgress * opt.ms;
              }}
              style={{
                fontFamily: 'Orbitron, sans-serif', fontSize: 10, padding: '4px 8px', borderRadius: 4,
                border: 'none', cursor: 'pointer', transition: 'all 0.15s',
                background: speedIdx === i ? 'rgba(225, 6, 0, 0.35)' : 'transparent',
                color: speedIdx === i ? '#ff4444' : 'rgba(255, 255, 255, 0.45)',
                fontWeight: speedIdx === i ? 700 : 400,
              }}
            >
              {opt.label}
            </button>
          ))}
        </div>

        {/* Show drivers count */}
        <div style={{ display: 'flex', alignItems: 'center', gap: 4 }}>
          <span style={{ fontSize: 9, color: 'rgba(255, 255, 255, 0.35)', textTransform: 'uppercase', fontFamily: 'Orbitron, sans-serif', letterSpacing: 1 }}>
            Show
          </span>
          <select
            value={showTopN}
            onChange={e => setShowTopN(Number(e.target.value))}
            style={{
              fontFamily: 'Orbitron, sans-serif', fontSize: 10, padding: '3px 6px', borderRadius: 4,
              border: '1px solid rgba(255, 255, 255, 0.12)', background: 'rgba(255, 255, 255, 0.06)',
              color: 'rgba(255, 255, 255, 0.7)', cursor: 'pointer',
            }}
          >
            <option value={5}>Top 5</option>
            <option value={10}>Top 10</option>
            <option value={15}>Top 15</option>
            <option value={20}>All 20</option>
          </select>
        </div>
      </div>
    </div>
  );
};

const stepBtnStyle: React.CSSProperties = {
  fontFamily: 'Orbitron, sans-serif', fontSize: 12, padding: '4px 10px', borderRadius: 6,
  border: '1px solid rgba(255, 255, 255, 0.1)', background: 'rgba(255, 255, 255, 0.04)',
  color: 'rgba(255, 255, 255, 0.6)', cursor: 'pointer',
};

export default RaceReplay;
